export function mergePolish12CatalogIntoLocales(locales: Record<string, Record<string, unknown>>): void {
  for (const locale of Object.keys(POLISH12_CATALOG_I18N)) {
    const pack = POLISH12_CATALOG_I18N[locale];
    if (!pack || !locales[locale]) continue;
    const game = locales[locale].game as Record<string, unknown> | undefined;
    if (game) {
      const classes = (game.classes as Record<string, unknown>) || (game.classes = {});
      const evolution = (classes.evolution as Record<string, unknown>) || (classes.evolution = {});
      Object.assign(evolution, {
        names: { ...(evolution.names as object), ...pack.classNames },
        desc: { ...(evolution.desc as object), ...pack.classDesc },
      });
    }
    const creation = (locales[locale].creation as Record<string, unknown>) || (locales[locale].creation = {});
    Object.assign(creation, {
      raceNames: { ...(creation.raceNames as object), ...pack.raceNames },
      raceDesc: { ...(creation.raceDesc as object), ...pack.raceDesc },
    });
    const olympiad = (locales[locale].olympiad as Record<string, unknown>) || (locales[locale].olympiad = {});
    Object.assign(olympiad, {
      ranks: { ...(olympiad.ranks as object), ...pack.ranks },
      tierNames: { ...(olympiad.tierNames as object), ...pack.tierNames },
    });
  }
}

export {};